        for (pn,pl) in preds:
            av=x[v,pn,j]
            m.addCons(ld[v,j] >= pl+pu[v,j]-do[v,j]-BM*(1-av))
            m.addCons(ld[v,j] <= pl+pu[v,j]-do[v,j]+BM*(1-av))
        m.addCons(ld[v,j]<=BM*vis[v,j])

for i in SI:
    tpu=quicksum(pu[v,i] for v in V); tdo=quicksum(do[v,i] for v in V)
    fin=initb[i]-tpu+tdo
    m.addCons(fin>=0); m.addCons(fin<=scap[i])

for i in SI:
